// find-email: find all email addresses in a string using regexped WASM.
// stub.ts is auto-generated by: regexped generate --config=regexped.yaml
import { find_email } from "./stub";

function slice(buf: ArrayBuffer, start: i32, end: i32): string {
  return String.UTF8.decodeUnsafe(changetype<usize>(buf) + <usize>start, <usize>(end - start), false);
}

function findEmails(text: string): void {
  console.log("input: " + text);
  const buf = String.UTF8.encode(text);
  let off: i32 = 0;
  let found = false;
  while (true) {
    const slots = find_email(buf, off);
    if (!slots) break;
    found = true;
    const matchStart = load<i32>(slots);
    const matchEnd   = load<i32>(slots + 4);
    const userStart  = load<i32>(slots + 8);
    const userEnd    = load<i32>(slots + 12);
    const domStart   = load<i32>(slots + 16);
    const domEnd     = load<i32>(slots + 20);
    console.log("  email:  " + slice(buf, matchStart, matchEnd));
    console.log("    user:   " + slice(buf, userStart, userEnd));
    console.log("    domain: " + slice(buf, domStart, domEnd));
    off = matchEnd > matchStart ? matchEnd : matchStart + 1;
  }
  if (!found) {
    console.log("  (no emails found)");
  }
}

findEmails("Contact alice@example.com or bob@company.org for details.");
findEmails("reach us at support@open-source.io and sales@widgets.co.uk");
findEmails("no emails here");
